// ── WorkoutEngine.ts ─────────────────────────────────────────────────────────
// 100+ bodyweight / no-equipment exercise library + structured workout generator

export type MuscleGroup =
    | "chest" | "back" | "shoulders" | "biceps" | "triceps" | "forearms"
    | "core" | "glutes" | "quads" | "hamstrings" | "calves" | "full_body" | "cardio"
    | "obliques" | "adductors" | "hip_flexors"
    | "rear_delts" | "rhomboids" | "traps" | "rotator_cuff" | "lower_back" | "grip" | "lats" | "arms"
    | "front_delts" | "upper_chest" | "neck" | "lower_abs" | "upper_abs";

export type Equipment =
    | "bodyweight" | "pull_up_bar" | "bench" | "wall" | "chair"
    | "resistance_band" | "backpack" | "towel" | "floor"
    | "barbell" | "dumbbell" | "cable" | "machine" | "kettlebell" | "bands";

export type Goal = "hypertrophy" | "strength" | "endurance" | "fat_loss" | "mobility" | "powerbuilding";
export type Focus = string;

// ── NEW: Engine parameters ────────────────────────────────────────────────────
export type Duration = 15 | 30 | 45 | 60;
export type Intensity = "beginner" | "intermediate" | "advanced";
export type WorkoutStyle = "strength_hypertrophy" | "hiit" | "mobility_flow" | "isometrics";

export interface Exercise {
    id: string;
    name: string;
    muscleGroup: MuscleGroup;
    secondaryMuscles: MuscleGroup[];
    equipment: Equipment[];
    difficulty: 1 | 2 | 3;          // 1=beginner, 2=intermediate, 3=advanced
    isCompound: boolean;
    modality: "strength" | "plyometric" | "isometric" | "mobility" | "cardio";
    instructions: string;
    imageUrl: string;
    cue?: string;                    // coaching cue
    duration_s?: number;             // for timed exercises
}

export interface GeneratedSet {
    reps: string;          // e.g. "8-12" or "45s" for timed
    restSeconds: number;
    rpe?: number;
    weightKg?: number;
    isWarmup?: boolean;
}

export interface GeneratedExercise {
    exercise: Exercise;
    sets: GeneratedSet[];
}

export interface GeneratedWorkout {
    id: string;
    name: string;
    emoji: string;
    color: string;
    focus: string[];
    musclesWorked: MuscleGroup[];
    estimatedMinutes: number;
    warmup: GeneratedExercise[];
    working: GeneratedExercise[];
    cooldown: GeneratedExercise[];
    goal: Goal;
    // NEW metadata
    duration: Duration;
    intensity: Intensity;
    style: WorkoutStyle;
    restSeconds: number;
    rpeLabel: string;
}

// ── Focus + Goal options exposed to UI ───────────────────────────────────────

