// ── Workout Generation Config ─────────────────────────────────────────────────

export interface GenerateOptions {
    focus: Focus;
    goal: Goal;
    availableEquipment: Equipment[];
    difficulty?: 1 | 2 | 3;
    duration?: Duration;
    intensity?: Intensity;
    style?: WorkoutStyle;
}

const GOAL_SCHEME: Record<Goal, { sets: number; reps: string; rest: number; rpe: number }> = {
    hypertrophy: { sets: 3, reps: "8-12", rest: 60, rpe: 8 },
    strength: { sets: 4, reps: "4-6", rest: 120, rpe: 9 },
    endurance: { sets: 3, reps: "15-20", rest: 45, rpe: 7 },
    fat_loss: { sets: 4, reps: "12-15", rest: 30, rpe: 8 },
    mobility: { sets: 2, reps: "60s hold", rest: 30, rpe: 5 },
    powerbuilding: { sets: 4, reps: "5-8", rest: 90, rpe: 8 },
};

const FOCUS_TO_MUSCLES: Record<string, MuscleGroup[]> = {
    "full body": ["chest", "back", "quads", "glutes", "shoulders", "core"],
    "push": ["chest", "shoulders", "triceps"],
    "pull": ["back", "biceps", "forearms"],
    "legs": ["quads", "hamstrings", "glutes", "calves"],
    "chest": ["chest"],
    "back": ["back"],
    "shoulders": ["shoulders"],
    "glutes": ["glutes"],
    "arms": ["biceps", "triceps", "forearms"],
    "core": ["core", "obliques", "lower_back"],
    "cardio": ["cardio"],
    "hiit": ["cardio", "quads", "core"],
    "plyo": ["quads", "calves", "cardio"],
    "mobility": ["full_body", "core", "hip_flexors"],
    "upper body": ["chest", "back", "shoulders", "arms"],
    "lower body": ["quads", "hamstrings", "glutes", "calves"],
};

const FOCUS_COLOR: Record<string, string> = {
    "full body": "#8B5CF6", // Purple
    "push": "#3B82F6",      // Blue
    "pull": "#A855F7",      // Purple
    "legs": "#22C55E",      // Green
    "chest": "#3B82F6",
    "back": "#A855F7",
    "shoulders": "#06B6D4", // Cyan
    "glutes": "#EF4444",    // Red
    "arms": "#F97316",      // Orange
    "core": "#F59E0B",      // Amber
    "cardio": "#EF4444",    // Red
    "hiit": "#EF4444",
    "plyo": "#14B8A6",      // Teal
    "mobility": "#10B981",  // Emerald
    "upper body": "#3B82F6",
    "lower body": "#22C55E",
};

// Simple array shuffle
function shuffle<T>(array: T[]): T[] {
    const arr = [...array];
    for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
}

export function generateWorkout(opts: GenerateOptions): GeneratedWorkout {
    const {
        focus, goal, availableEquipment,
        difficulty = 2,
        duration = 45,
        intensity = "intermediate",
        style = "strength_hypertrophy",
    } = opts;

    const scheme = GOAL_SCHEME[goal];
    const targetMuscles = FOCUS_TO_MUSCLES[focus] ?? ["full_body"];
    const intensityConfig = INTENSITY_CONFIG[intensity];
    const styleConfig = STYLE_CONFIG[style];

    // How many exercises to pick based on duration
    const exerciseCount = DURATION_EXERCISE_COUNT[duration];

    // Effective difficulty cap from intensity
    const effectiveDifficultyMax = intensityConfig.difficultyMax;

    // Rest = goal base × intensity multiplier ± style adjustment
    const baseRest = scheme.rest;
    const computedRest = Math.max(15, Math.round(baseRest * intensityConfig.restMultiplier + styleConfig.restAdjust));

    // Sets scaled by intensity
    const computedSets = Math.max(1, Math.round(scheme.sets * intensityConfig.setsMultiplier));

    // Filter exercises by equipment AND difficulty
    const eligible = EXERCISE_DATABASE.filter(ex =>
        ex.equipment.some(eq => availableEquipment.includes(eq)) &&
        ex.difficulty <= effectiveDifficultyMax
    );

    // Style dictates modality
    const modalFilter = styleConfig.modalFilter;
    // Override modality for specific goals
    const effectiveModalFilter = goal === "mobility"
        ? ["mobility", "isometric"]
        : goal === "fat_loss" || focus === "hiit" || style === "hiit"
            ? ["strength", "plyometric", "cardio", "isometric"]
            : modalFilter;

    const working_candidates = eligible.filter(ex =>
        (targetMuscles.includes(ex.muscleGroup) || ex.secondaryMuscles.some(sm => targetMuscles.includes(sm))) &&
        effectiveModalFilter.includes(ex.modality)
    );

    // Compounds first, then isolation
    const compounds = shuffle(working_candidates.filter(e => e.isCompound));
    const isolations = shuffle(working_candidates.filter(e => !e.isCompound));
    const workingExercises = [...compounds, ...isolations].slice(0, exerciseCount);

    // Warmup: 2-3 mobility/low-difficulty exercises
    const warmupCandidates = shuffle(eligible.filter(ex =>
        (ex.modality === "mobility" || ex.difficulty === 1) &&
        !workingExercises.includes(ex)
    ));
    const warmupCount = duration <= 15 ? 1 : duration <= 30 ? 2 : 3;
    const warmupExercises = warmupCandidates.slice(0, warmupCount);

    const buildSet = (ex: Exercise, is_warmup: boolean): GeneratedSet => {
        const isDuration = !!ex.duration_s;
        return {
            reps: isDuration ? `${ex.duration_s}s` : scheme.reps,
            restSeconds: is_warmup ? 30 : computedRest,
            rpe: is_warmup ? 5 : scheme.rpe,
            weightKg: 0,
            isWarmup: is_warmup,
        };
    };

    const warmup: GeneratedExercise[] = warmupExercises.map(ex => ({
        exercise: ex,
        sets: [buildSet(ex, true)],
    }));

    const working: GeneratedExercise[] = workingExercises.map(ex => ({
        exercise: ex,
        sets: Array.from({ length: computedSets }, () => buildSet(ex, false)),
    }));

    const musclesWorked: MuscleGroup[] = Array.from(new Set([
        ...workingExercises.map(e => e.muscleGroup),
        ...workingExercises.flatMap(e => e.secondaryMuscles),
    ]));

    const estimatedMinutes = Math.min(duration, Math.round(
        warmup.length * 1.5 +
        working.reduce((acc, ge) => acc + ge.sets.length * ((computedRest + 40) / 60), 0)
    ));

    const color = FOCUS_COLOR[focus] ?? "#3B82F6";
    const emoji = styleConfig.emoji;

    const focusLabel = focus.charAt(0).toUpperCase() + focus.slice(1);
    const styleLabel = styleConfig.label;

    return {
        id: `gen_${Date.now()}`,
        name: `${focusLabel} ${styleLabel}`,
        emoji,
        color,
        focus: [focus],
        musclesWorked,
        estimatedMinutes,
        warmup,
        working,
        cooldown: [],
        goal,
        duration,
        intensity,
        style,
        restSeconds: computedRest,
        rpeLabel: intensityConfig.rpeLabel,
    };
}
